-- ============================================================================
-- Seeds the 'Rekreacja' specialization topics (track = 'rekreacja') into
-- public.topics. Incremental migration: the base content migration was already
-- applied to existing DBs, so this later-timestamped file is what actually
-- delivers the new rows on `supabase migration up` / `db push`. Upsert, scoped
-- to rekreacja only — does not touch the other tracks or rebalanced answers.
-- 30 topics.
-- ============================================================================

insert into public.topics (id, track, category, number, title, summary, wiki, questions)
select id, track, category, number, title, summary, wiki, questions
from jsonb_to_recordset($awfjson$[{"id":"rek-wskaznik-antropometryczny","track":"rekreacja","category":"rekreacja-spec","number":1,"title":"Wskaźniki antropometryczne i ich zastosowanie","summary":"Wskaźnik antropometryczny to stosunek dwóch lub więcej pomiarów ciała, który pozwala ocenić jego proporcje, stan odżywienia lub ryzyko chorób.","wiki":[{"heading":"Czym jest wskaźnik antropometryczny","body":"Wskaźnik antropometryczny to stosunek dwóch lub więcej pomiarów ciała, które pozwalają ocenić proporcje ciała, stan odżywienia lub ryzyko chorób. Zasadą tworzenia wskaźników jest ustosunkowanie pomiaru o mniejszej liczbowo wartości do cechy o wartości większej."},{"heading":"Wysokość ciała w ergonomii","body":"Wysokość ciała to cecha wykorzystywana w ergonomii. Właściwości budowy ciała człowieka warunkują kształtowanie struktury przestrzennej miejsca pracy oraz jej elementów składowych: rozmiarów siedzisk i urządzeń pracowniczych oraz optymalnego rozmieszczenia tych elementów względem siebie i względem użytkownika. Pomiary antropometryczne opisują sylwetkę wyprostowaną (antropometria klasyczna: statyczna i dynamiczna) oraz naturalną, jaką przyjmuje człowiek podczas wykonywanej czynności (antropometria ergonomiczna)."},{"heading":"BMI (Indeks Masy Ciała)","body":"BMI (Body Mass Index) to popularny wskaźnik, który pomaga ocenić proporcje masy ciała do wzrostu i jest stosunkowo łatwy w obliczeniach. Uzyskany wynik porównuje się z tabelą i kwalifikuje do jednej z czterech kategorii: niedowaga, waga prawidłowa, nadwaga lub otyłość.","bullets":["ocena masy ciała","rozpoznanie otyłości","pomoc dla specjalistów w planowaniu diety i treningów"]},{"heading":"Ograniczenia BMI","body":"Przy BMI należy pamiętać, że nie rozróżnia on masy mięśniowej od masy tłuszczowej. Przez to wynik BMI osoby ćwiczącej profesjonalnie, na przykład kulturysty, może wskazywać otyłość, choć w rzeczywistości nią nie jest."}],"questions":[{"type":"abcd","q":"Do ilu kategorii kwalifikuje się wynik BMI?","options":["Do trzech","Do pięciu","Do dwóch","Do czterech"],"correct":3,"explain":"Wynik BMI kwalifikuje się do jednej z czterech kategorii: niedowaga, waga prawidłowa, nadwaga lub otyłość."},{"type":"tf","q":"BMI rozróżnia masę mięśniową od masy tłuszczowej.","correct":false,"explain":"BMI nie rozróżnia masy mięśniowej od tłuszczowej, dlatego u kulturysty może błędnie wskazywać otyłość."},{"type":"tf","q":"Zasadą tworzenia wskaźników antropometrycznych jest ustosunkowanie pomiaru o mniejszej wartości liczbowej do cechy o wartości większej.","correct":true,"explain":"To właśnie ta zasada leży u podstaw konstruowania wskaźników antropometrycznych."},{"type":"flash","front":"Czym jest wskaźnik antropometryczny?","back":"To stosunek dwóch lub więcej pomiarów ciała, pozwalający ocenić proporcje ciała, stan odżywienia lub ryzyko chorób."}]},{"id":"rek-nordic-walking-wszechstronnosc","track":"rekreacja","category":"rekreacja-spec","number":2,"title":"Wszechstronność nordic walking","summary":"Nordic walking jest wszechstronną formą aktywności, ponieważ angażuje niemal wszystkie mięśnie ciała, poprawia wydolność oraz wzmacnia stawy i kręgosłup.","wiki":[{"heading":"Dlaczego nordic walking jest wszechstronny","body":"Nordic walking jest wszechstronną formą aktywności ruchowej, ponieważ angażuje niemal wszystkie mięśnie ciała, poprawia wydolność, wzmacnia stawy i kręgosłup, a także pozytywnie wpływa na samopoczucie. To kompleksowa forma aktywności, która przynosi liczne korzyści zdrowotne i może być uprawiana przez każdego, niezależnie od wieku czy poziomu sprawności."},{"heading":"Główne korzyści","bullets":["aktywacja mięśni — angażuje aż do 90% mięśni ciała, w tym rąk, barków, nóg i tułowia, znacznie więcej niż zwykły spacer","poprawa wydolności tlenowej, pracy serca i układu krążenia oraz spalanie kalorii","wzmocnienie stawów i kości — kijki odciążają stawy kolanowe i biodrowe, wzmacniając kości i zapobiegając osteoporozie","poprawa koordynacji i równowagi dzięki skoordynowanemu ruchowi rąk i nóg","redukcja stresu — ruch na świeżym powietrzu sprzyja produkcji endorfin"]},{"heading":"Dostępność i rehabilitacja","body":"Nordic walking jest odpowiedni dla osób w każdym wieku i o różnym poziomie sprawności, a jedyny potrzebny sprzęt to kije i wygodne buty. Może być również pomocny w procesie rehabilitacji po urazach lub operacjach, ponieważ odciąża stawy i pozwala na stopniowy powrót do aktywności fizycznej."}],"questions":[{"type":"abcd","q":"Jaki odsetek mięśni ciała angażuje nordic walking?","options":["Aż do 90%","Około 50%","Aż do 70%","Około 30%"],"correct":0,"explain":"Nordic walking angażuje aż do 90% mięśni ciała, znacznie więcej niż zwykły spacer."},{"type":"tf","q":"Chodzenie z kijkami obciąża stawy kolanowe i biodrowe bardziej niż zwykły spacer.","correct":false,"explain":"Przeciwnie — kijki odciążają stawy kolanowe i biodrowe, jednocześnie wzmacniając kości."},{"type":"tf","q":"Nordic walking może być pomocny w procesie rehabilitacji po urazach lub operacjach.","correct":true,"explain":"Odciąża stawy i pozwala na stopniowy powrót do aktywności fizycznej, dlatego bywa wykorzystywany w rehabilitacji."},{"type":"flash","front":"Jaki sprzęt jest potrzebny do uprawiania nordic walking?","back":"Jedynie kije do nordic walking oraz wygodne buty."}]},{"id":"rek-sport-zjawisko-spoleczne","track":"rekreacja","category":"rekreacja-spec","number":3,"title":"Sport jako zjawisko społeczne","summary":"Sport jest złożonym fenomenem kulturowo-społecznym, który od ponad 2000 lat towarzyszy relacjom społecznym i spełnia wiele funkcji.","wiki":[{"heading":"Sport w świetle ustawy o sporcie","body":"Zgodnie z ustawą z dnia 25 czerwca 2010 r. o sporcie, sportem są wszelkie formy aktywności fizycznej, które przez uczestnictwo doraźne lub zorganizowane wpływają na wypracowanie lub poprawienie kondycji fizycznej i psychicznej, rozwój stosunków społecznych lub osiągnięcie wyników sportowych na wszelkich poziomach. Za sport uważa się również współzawodnictwo oparte na aktywności intelektualnej, którego celem jest osiągnięcie wyniku sportowego."},{"heading":"Sport a kultura fizyczna","body":"Sport wraz z wychowaniem fizycznym i rehabilitacją ruchową składa się na kulturę fizyczną, czyli ogół zachowań przebiegających według przyjętych w danym środowisku reguł i norm, mających na celu dbałość o zdrowie człowieka, poprawę jego postawy i prawidłowy rozwój psychofizyczny. Sport to z założenia pokojowe współzawodnictwo prowadzone zgodnie z zasadami fair play, rozwijające cechy osobowości, takie jak wytrwałość, silna wola, zdyscyplinowanie oraz poczucie solidarności i koleżeństwa."},{"heading":"Funkcje i znaczenie społeczne","bullets":["spełnia wiele funkcji: wychowawczą, integracyjną, zdrowotną, rozrywkową, edukacyjną i terapeutyczną","jest ważnym czynnikiem integrującym różne środowiska społeczne o zasięgu lokalnym, regionalnym i międzynarodowym","przyczynił się do rozwoju budownictwa sportowego oraz przemysłowej produkcji sprzętu","od ponad 2000 lat towarzyszy relacjom społecznym i kulturowym, stając się ich nieodłączną częścią"]},{"heading":"Sport jako przedmiot badań","body":"Sport nie jest jedynie aktywnością fizyczną, lecz złożonym fenomenem kulturowo-społecznym. Analizowany jest przez wiele nauk społecznych i humanistycznych: socjologię, filozofię, psychologię, pedagogikę, historię, politologię, a nawet prawo i ekonomię. Filozofia sportu analizuje jego sens, wartości i bytowość (ontologia), a socjologia bada jego wpływ na strukturę społeczną, role społeczne i tożsamość jednostek."}],"questions":[{"type":"abcd","q":"Które elementy razem ze sportem składają się na kulturę fizyczną?","options":["Turystyka i rekreacja","Wychowanie fizyczne i rehabilitacja ruchowa","Edukacja i rozrywka","Polityka i ekonomia"],"correct":1,"explain":"Sport wraz z wychowaniem fizycznym i rehabilitacją ruchową składa się na kulturę fizyczną."},{"type":"tf","q":"Zgodnie z ustawą o sporcie za sport uważa się również współzawodnictwo oparte na aktywności intelektualnej.","correct":true,"explain":"Ustawa uznaje za sport współzawodnictwo intelektualne, którego celem jest osiągnięcie wyniku sportowego."},{"type":"tf","q":"Sport towarzyszy relacjom społecznym i kulturowym dopiero od około 200 lat.","correct":false,"explain":"Sport jest trwale wpisany w życie społeczne od ponad 2000 lat, a nie od 200 lat."},{"type":"flash","front":"Jakie nauki analizują zjawisko sportu?","back":"Socjologia, filozofia, psychologia, pedagogika, historia, politologia, a nawet prawo i ekonomia."}]},{"id":"rek-narciarstwo-grupy-wiekowe","track":"rekreacja","category":"rekreacja-spec","number":4,"title":"Nauczanie narciarstwa w różnych grupach wiekowych","summary":"Zadania w nauce narciarstwa stopniuje się według wieku i poziomu uczestników — od zabawowego oswajania ze sprzętem u dzieci po spokojne, asekurowane ćwiczenia seniorów.","wiki":[{"heading":"Dzieci (3–12 lat)","body":"Zajęcia rozpoczynają się oswojeniem ze sprzętem: chodzeniem w butach narciarskich, utrzymaniem równowagi i prostymi ślizgami w pług na płaskim terenie. Nauka odbywa się przez zabawę, z krótkimi seriami ćwiczeń (10–15 min) i częstymi przerwami. Trudność stopniuje się od niemal płaskiego terenu do bardzo łagodnych wzniesień, zawsze z asekuracją. Grupy są małe (4–6 osób), a ze względu na wrażliwość na zimno i słabiej rozwinięte mięśnie konieczne są ciepłe przerwy oraz lekki sprzęt."},{"heading":"Młodzież (13–18 lat)","body":"Nastolatki zaczynają od przypomnienia podstaw, przechodząc do ćwiczeń technicznych: płużnych skrętów, slalomu między pachołkami i muld. Nauka odbywa się na stokach zielonych i łatwych niebieskich, z naciskiem na kontrolę prędkości, samodzielne hamowanie i refleks. Po opanowaniu podstaw wprowadza się elementy współzawodnictwa, np. slalom na czas. Grupy liczą 6–10 osób."},{"heading":"Dorośli (19–60 lat)","body":"Lekcję rozpoczyna omówienie sprzętu i zasad bezpieczeństwa (numery GOPR), a następnie demonstracja podstaw: pozycji, trzymania kijków i wstawania z upadku. Ćwiczenia na śniegu prowadzi się stopniowo — od ześlizgu w pług po jazdę łukiem płużnym — z przerwami na stretching. Grupy są małe (4–6 osób), dobrane według kondycji i poziomu lęku, a metoda demonstracyjna i analityczna pozwala na logiczną rozbiórkę ruchu."},{"heading":"Seniorzy (60+)","body":"Zajęcia zaczynają się od łagodnej rozgrzewki stawów, a następnie spokojnych, powtarzanych ćwiczeń na łagodnym stoku, w tym ćwiczeń równowagi. Każdy ruch wykonuje się wolno, z asekuracją i przerwami na kontrolę pulsu oraz ogrzanie. Grupy są bardzo małe (2–4 osoby) lub zajęcia są indywidualne. Ze względu na wolniejszy czas reakcji i pogorszenie równowagi unika się gwałtownych ruchów i nadmiernej prędkości, a przerwy z ciepłymi napojami są obowiązkowe."}],"questions":[{"type":"abcd","q":"Ilu osób liczą zwykle grupy seniorów (60+) na zajęciach narciarskich?","options":["6–10 osób","4–6 osób","2–4 osoby lub zajęcia indywidualne","10–15 osób"],"correct":2,"explain":"Grupy seniorów są bardzo małe — 2–4 osoby — lub zajęcia prowadzone są indywidualnie."},{"type":"tf","q":"U dzieci naukę narciarstwa prowadzi się głównie przez zabawę, z krótkimi seriami ćwiczeń i częstymi przerwami.","correct":true,"explain":"Dzieci uczą się przez zabawę, w krótkich seriach 10–15 min, z częstymi i ciepłymi przerwami."},{"type":"tf","q":"U seniorów ćwiczenia kładą nacisk na gwałtowne ruchy i jazdę z dużą prędkością.","correct":false,"explain":"U seniorów unika się gwałtownych ruchów i nadmiernej prędkości, stawiając na spokojne, asekurowane ćwiczenia."},{"type":"flash","front":"Na jakich stokach uczy się narciarstwa młodzież (13–18 lat)?","back":"Na stokach zielonych i łatwych niebieskich, z naciskiem na kontrolę prędkości i samodzielne hamowanie."}]},{"id":"rek-gry-miejskie-produkt-turystyczny","track":"rekreacja","category":"rekreacja-spec","number":5,"title":"Gry miejskie jako produkt turystyczny","summary":"Gry miejskie to innowacyjna, aktywna alternatywa dla tradycyjnego zwiedzania z przewodnikiem, łącząca poznawanie miasta z integracją i wykonywaniem zadań.","wiki":[{"heading":"Czym są gry miejskie","body":"Gry miejskie są wykorzystywane w branży turystycznej jako bardziej interesująca alternatywa dla tradycyjnego zwiedzania miasta z przewodnikiem. Zakładają aktywne zwiedzanie miasta, włączając w to integrację uczestników. Posługując się przygotowaną przez organizatora mapą z wyznaczoną trasą, uczestnicy mają za cel zdobycie jak największej liczby punktów za wykonane zadania. Gra może mieć bardzo różną formę, np. strategicznej rozgrywki, zabawy integracyjnej, survivalu czy poszukiwania skarbów."},{"heading":"Przykłady poznańskich gier miejskich","bullets":["gry nawiązujące do wydarzeń historycznych — o początkach Państwa Polskiego („Poznań poza Czasem”)","gry o II wojnie światowej („Łamacze szyfrów”, „Enigma”, „Aresztuj Generała”, „Bitwa o Poznań”)","gra o okresie stanu wojennego („Raport z oblężonego miasta”)","gry związane z bieżącymi wydarzeniami, np. Mistrzostwami Europy w Piłce Nożnej 2012 („POZnań 2012”)"]},{"heading":"Projekt „Zwiedzaj grając – graj zwiedzając”","body":"Poznański zespół gramiejska.pl we współpracy z Poznańską Lokalną Organizacją Turystyczną realizuje projekt „Zwiedzaj grając – graj zwiedzając”. Oferta skierowana jest głównie do turystów, ale także do mieszkańców, by promować różne części miasta. Należą do niej m.in. „Pierwszy stopień poznania” (śladami zabytków Ostrowa Tumskiego i Śródki), „Czas patriotów” (szlakiem miejsc Powstania Wielkopolskiego) oraz „Poznań poza czasem” (w obrębie Traktu Królewsko-Cesarskiego)."},{"heading":"Atuty gier miejskich","body":"Gry miejskie wkraczają w fazę dynamicznego rozwoju jako alternatywa dla zwiedzania z przewodnikiem. Rozwiązywanie zadań dodatkowo motywuje do dokładnego poznawania miejsc. Dodatkowym atutem jest zejście z uczęszczanych ścieżek oraz interakcje z lokalnymi mieszkańcami, co raczej nie jest możliwe przy tradycyjnym przewodniku. Dzięki dobrze zaprojektowanej grze miasto może wzmocnić swój przekaz o historii i współczesności."}],"questions":[{"type":"abcd","q":"Co jest głównym celem uczestników gry miejskiej?","options":["Jak najszybsze ukończenie trasy","Spotkanie z przewodnikiem","Zdobycie jak największej liczby punktów za wykonane zadania","Zwiedzanie wyłącznie głównych zabytków"],"correct":2,"explain":"Uczestnicy, korzystając z mapy z wyznaczoną trasą, dążą do zdobycia jak największej liczby punktów za wykonane zadania."},{"type":"tf","q":"Gry miejskie umożliwiają zejście z uczęszczanych ścieżek oraz interakcje z lokalnymi mieszkańcami.","correct":true,"explain":"To jeden z atutów gier miejskich, trudny do osiągnięcia przy tradycyjnym zwiedzaniu z przewodnikiem."},{"type":"tf","q":"Projekt „Zwiedzaj grając – graj zwiedzając” jest skierowany wyłącznie do mieszkańców Poznania.","correct":false,"explain":"Oferta skierowana jest głównie do turystów, ale także do mieszkańców miasta."},{"type":"flash","front":"Jaką formę mogą przyjmować gry miejskie?","back":"Np. strategicznej rozgrywki, zabawy integracyjnej, survivalu czy poszukiwania skarbów."}]},{"id":"rek-impreza-rekreacyjna-istota-etapy","track":"rekreacja","category":"rekreacja-spec","number":6,"title":"Istota imprezy rekreacyjnej i etapy jej organizacji","summary":"Impreza rekreacyjna to wydarzenie organizowane w celu promocji aktywności fizycznej podejmowanej w wolnym czasie, a jej przygotowanie przebiega według kolejnych etapów organizacyjnych.","wiki":[{"heading":"Czym jest impreza rekreacyjna","body":"Impreza rekreacyjna to wydarzenie organizowane w celu promocji aktywności fizycznej podejmowanej w wolnym czasie. Jej organizacja to złożony proces, który wymaga zaangażowania wielu osób, a skuteczna realizacja przyczynia się do pozytywnego doświadczenia uczestników oraz budowania pozytywnego wizerunku organizatora."},{"heading":"Istota imprez rekreacyjnych","bullets":["Rozrywka – poczucie przyjemności odczuwane przez uczestników poprzez udział w wydarzeniu","Relaks – możliwość odpoczynku od ciągłego pełnienia roli w społeczeństwie, czas dla siebie","Integracja społeczna – kontakt z innymi ludźmi o podobnych celach","Aktywność fizyczna – każda dodatkowa ilość ruchu w tygodniu pozytywnie wpływa na organizm","Edukacja – promowanie zdrowego stylu życia i zachęcanie do zdrowych wyborów"]},{"heading":"Etapy organizacji imprezy","bullets":["Pomysł na imprezę – określenie celu i tematu przewodniego wydarzenia","Zdobycie budżetu i pozyskanie sponsorów – kluczowy punkt finansujący przedsięwzięcie","Stworzenie zespołu – podział na grupy oraz podział zadań i odpowiedzialności","Przygotowanie programu i atrakcji – jednocześnie zabezpieczenie medyczne, regulamin oraz promocja i marketing","Koordynacja w dniu imprezy","Podsumowanie imprezy – zebranie opinii, ocena realizacji celów i wnioski na przyszłość"]}],"questions":[{"type":"abcd","q":"W jakim celu organizuje się imprezę rekreacyjną?","options":["Promocji aktywności fizycznej podejmowanej w wolnym czasie","Wyłonienia mistrza w danej dyscyplinie sportu","Wyłącznie pozyskania środków finansowych dla organizatora","Przeprowadzenia badań naukowych nad uczestnikami"],"correct":0,"explain":"Impreza rekreacyjna to wydarzenie organizowane w celu promocji aktywności fizycznej podejmowanej w wolnym czasie."},{"type":"tf","q":"Zdobycie budżetu i pozyskanie sponsorów to ostatni etap organizacji imprezy rekreacyjnej.","correct":false,"explain":"Zdobycie budżetu i pozyskanie sponsorów to jeden z wczesnych etapów; ostatnim etapem jest podsumowanie imprezy."},{"type":"flash","front":"Wymień elementy stanowiące istotę imprez rekreacyjnych.","back":"Rozrywka, relaks, integracja społeczna, aktywność fizyczna oraz edukacja."},{"type":"flash","front":"Co dzieje się na etapie podsumowania imprezy?","back":"Zebranie opinii, ocena realizacji celów oraz wyciągnięcie wniosków na przyszłość."}]},{"id":"rek-walory-poznawcze-narciarstwa-snowboardu","track":"rekreacja","category":"rekreacja-spec","number":7,"title":"Walory poznawcze narciarstwa i snowboardu","summary":"Uprawianie narciarstwa i snowboardu niesie liczne walory poznawcze i turystyczne – od poznawania nowych obszarów po rozwijanie umiejętności i przezwyciężanie własnych słabości.","wiki":[{"heading":"Walory poznawcze i turystyczne","bullets":["Poznawanie nowych obszarów oraz obcowanie z naturą","Nauka lub rozwijanie umiejętności jazdy, koordynacji ruchowej i równowagi","Rozwijanie umiejętności analitycznych i nawigacyjnych – planowanie trasy, ocena warunków, szybkie podejmowanie decyzji podczas zjazdów","Przezwyciężanie słabości – zjazdy z trudnych i stromych stoków w trudnych warunkach","Walory zdrowotne – ruch na świeżym powietrzu w połączeniu z krajobrazem gór wpływa pozytywnie także na zdrowie psychiczne","Integracja z bliskimi i innymi ludźmi","Doświadczanie radości i przyjemności z ruchu"]}],"questions":[{"type":"abcd","q":"Które umiejętności rozwija planowanie trasy i ocena warunków podczas jazdy?","options":["Wyłącznie umiejętności językowe","Umiejętności analityczne i nawigacyjne","Wyłącznie siłę mięśniową","Umiejętności kulinarne"],"correct":1,"explain":"Planowanie trasy i ocena warunków rozwijają umiejętności analityczne i nawigacyjne oraz szybkie podejmowanie decyzji podczas zjazdów."},{"type":"tf","q":"Ruch na świeżym powietrzu w górach pozytywnie wpływa także na zdrowie psychiczne.","correct":true,"explain":"Do walorów zdrowotnych zalicza się ruch na świeżym powietrzu, który w połączeniu z krajobrazem gór wpływa pozytywnie również na zdrowie psychiczne."},{"type":"flash","front":"Na czym polega walor poznawczy \"przezwyciężanie słabości\" w narciarstwie i snowboardzie?","back":"Na podejmowaniu zjazdów z trudnych i bardziej stromych stoków oraz w trudnych warunkach."}]},{"id":"rek-zaleznosci-rekreacja-praca","track":"rekreacja","category":"rekreacja-spec","number":8,"title":"Zależności pomiędzy rekreacją a pracą","summary":"Rekreacja i praca są ze sobą powiązane w sposób wpływający na efektywność i samopoczucie – rekreacja redukuje stres, ale nadmierne skupienie na pracy ogranicza czas na odpoczynek.","wiki":[{"heading":"Wzajemne powiązanie","body":"Rekreacja i praca są ze sobą powiązane w sposób, który może wpływać na efektywność i samopoczucie. Z jednej strony rekreacja pomaga w redukcji stresu i wypalenia zawodowego, co przekłada się na większą wydajność w pracy. Z drugiej strony nadmierne skupienie na pracy może ograniczać czas na aktywności rekreacyjne, co negatywnie wpływa na zdrowie psychiczne i fizyczne."},{"heading":"Zależności między pracą a rekreacją","bullets":["Redukcja stresu i wypalenia zawodowego","Poprawa koncentracji i kreatywności dzięki regeneracji umysłu","Wzrost motywacji i zaangażowania dzięki równowadze praca–życie prywatne","Poprawa zdrowia psychicznego i fizycznego","Budowanie relacji społecznych","Zwiększenie produktywności","Rozwój osobisty i większa satysfakcja z życia","Odskocznia od rutyny i codziennych obowiązków"]}],"questions":[{"type":"abcd","q":"Jaki wpływ na pracę ma redukcja stresu osiągana dzięki rekreacji?","options":["Obniża wydajność w pracy","Nie ma żadnego wpływu na pracę","Przekłada się na większą wydajność w pracy","Powoduje wypalenie zawodowe"],"correct":2,"explain":"Rekreacja pomaga w redukcji stresu i wypalenia zawodowego, co przekłada się na większą wydajność w pracy."},{"type":"tf","q":"Nadmierne skupienie na pracy korzystnie zwiększa ilość czasu przeznaczanego na aktywności rekreacyjne.","correct":false,"explain":"Przeciwnie – nadmierne skupienie na pracy ogranicza czas na aktywności rekreacyjne, co negatywnie wpływa na zdrowie psychiczne i fizyczne."},{"type":"flash","front":"W jaki sposób odpoczynek i aktywność rekreacyjna wpływają na umysł pracownika?","back":"Sprzyjają regeneracji umysłu, co przekłada się na lepszą koncentrację i kreatywność w pracy."},{"type":"flash","front":"Dlaczego rekreacja sprzyja budowaniu relacji społecznych?","back":"Czas wolny spędzany z rodziną i przyjaciółmi oraz udział w zajęciach rekreacyjnych w grupie sprzyja budowaniu i wzmacnianiu relacji, co jest ważne dla dobrostanu."}]},{"id":"rek-zasady-ekonomiczne-w-rekreacji","track":"rekreacja","category":"rekreacja-spec","number":9,"title":"Zasady ekonomiczne w rekreacji","summary":"Ekonomika rekreacji analizuje mechanizmy rządzące wykorzystaniem czasu wolnego i świadczeniem usług rekreacyjnych, czerpiąc z ekonomiki przedsiębiorstw.","wiki":[{"heading":"Ekonomika rekreacji","body":"Ekonomika rekreacji analizuje zasady i mechanizmy rządzące wykorzystaniem czasu wolnego oraz świadczeniem usług rekreacyjnych. Jej podstawy teoretyczne czerpią z ekonomiki przedsiębiorstw."},{"heading":"Zasady ekonomiczne w rekreacji","bullets":["Prawo popytu i podaży – im wyższa cena, tym mniejszy popyt, a większa podaż","Zasada ograniczoności zasobów – zasoby są rzadkie, więc trzeba odpowiadać na pytania: co, jak, ile i dla kogo produkować","Zasada racjonalnego gospodarowania – maksymalizacja efektu przy danych nakładach lub minimalizacja nakładów przy danych efektach","Zasada kosztu alternatywnego – koszt utraconych możliwości wynikający z wyboru jednego dobra zamiast innego","Zasada równowagi – przy pełnym wykorzystaniu zasobów zachodzi równość między podażą dóbr i usług a popytem na nie"]},{"heading":"Przykłady zastosowania","body":"Przykładem prawa popytu i podaży jest klub fitness, który po podniesieniu ceny karnetu uruchamia dodatkowe zajęcia wieczorne. Kosztem alternatywnym płatnych zajęć jogi w sobotę rano jest rezygnacja z bezpłatnego spaceru z rodziną – nie tylko pieniądze, ale i czas. Zasadę równowagi ilustruje gmina ustalająca opłatę za wejście do parku tak, by pokryć koszty utrzymania bez nadwyżki ani deficytu."}],"questions":[{"type":"abcd","q":"Z czego czerpie swoje podstawy teoretyczne ekonomika rekreacji?","options":["Z biologii sportu","Z psychologii społecznej","Z teorii prawa pracy","Z ekonomiki przedsiębiorstw"],"correct":3,"explain":"Podstawy teoretyczne ekonomiki rekreacji czerpią z ekonomiki przedsiębiorstw."},{"type":"tf","q":"Charakterystyczną cechą zasobów jest ich rzadkość, dlatego trzeba nimi umiejętnie gospodarować.","correct":true,"explain":"Zasada ograniczoności zasobów wskazuje, że zasoby są rzadkie i ich ilość jest ograniczona, więc społeczeństwo musi nimi umiejętnie gospodarować."},{"type":"abcd","q":"Czego dotyczy zasada kosztu alternatywnego?","options":["Ilości innego dobra, którego nie można uzyskać wskutek wyboru danego dobra","Łącznej sumy wszystkich kosztów stałych przedsiębiorstwa","Maksymalnej ceny, jaką klient zapłaci za usługę","Liczby pracowników potrzebnych do realizacji usługi"],"correct":0,"explain":"Koszt alternatywny danego dobra to ilość innego dobra, którego nie można uzyskać, ponieważ podjęto decyzję o wyborze tego pierwszego; bywa nazywany kosztem utraconych możliwości."},{"type":"flash","front":"Na czym polega zasada racjonalnego gospodarowania?","back":"Na alokowaniu ograniczonych zasobów tak, by zmaksymalizować efekt przy założonych nakładach lub zminimalizować nakłady przy założonych efektach."}]},{"id":"rek-niska-temperatura-gory-wysilek","track":"rekreacja","category":"rekreacja-spec","number":10,"title":"Znaczenie niskiej temperatury w górach podczas wysiłku","summary":"W warunkach górskich organizm broni temperatury ciała poprzez obwodową wazokonstrykcję i termogenezę, jednak chłód obniża funkcje mięśni, koordynację i sprawność umysłową oraz grozi hipotermią.","wiki":[{"heading":"Reakcje obronne organizmu","body":"Pierwszą reakcją na zimno jest obwodowa wazokonstrykcja – skurcz naczyń w skórze, a przy większym wychłodzeniu także w mięśniach i narządach wewnętrznych. Powoduje to centralizację krążenia, czyli kierowanie przepływu krwi do najważniejszych narządów: mózgu, serca i płuc, kosztem kończyn. Skóra wraz z podskórną tkanką tłuszczową tworzy izolujący \"płaszcz\" ograniczający utratę ciepła."},{"heading":"Termogeneza","body":"Gdy ochłodzenie postępuje, pojawia się termogeneza drżeniowa – mimowolne drżenie mięśni, które nawet 2,5-krotnie podnosi tempo metabolizmu i może zwiększyć spalanie węglowodanów niemal sześciokrotnie. Równocześnie termogeneza bezdrżeniowa, pobudzona wzrostem poziomu noradrenaliny, adrenaliny, glukagonu i trijodotyroniny, przyspiesza metabolizm bez drżeń. Szybkie zużycie glikogenu podczas wielogodzinnego wysiłku może jednak prowadzić do nagłego spadku sił."},{"heading":"Wpływ na mięśnie i koordynację","bullets":["Dyskomfort zaczyna się przy temperaturze skóry poniżej 25 °C","Siła mięśni spada o około 3% na każdy spadek temperatury ciała o 1 °C, a mięśnie stają się sztywne","Chłód wydłuża czas przewodzenia nerwowego – pojawiają się zaburzenia koordynacji i wolniejsze reakcje","Mimo chłodu dochodzi do odwodnienia – przez pocenie, suche powietrze i zwiększoną diurezę"]},{"heading":"Zagrożenia i przeciwdziałanie","body":"Długotrwałe przebywanie w niskiej temperaturze i wilgoci grozi hipotermią (spadek temperatury ciała poniżej 35 °C) oraz odmrożeniami, najczęściej palców rąk i stóp, nosa i małżowin usznych. Zimno obniża też sprawność umysłową: orientację w terenie, pamięć i szybkość decyzji. Aby temu przeciwdziałać, należy stosować odzież wielowarstwową i termoaktywną, dbać o regularne nawadnianie oraz planować tempo i przerwy umożliwiające regenerację."}],"questions":[{"type":"abcd","q":"Na czym polega centralizacja krążenia będąca reakcją organizmu na zimno?","options":["Na kierowaniu przepływu krwi do mózgu, serca i płuc kosztem kończyn","Na rozszerzeniu naczyń krwionośnych w skórze","Na całkowitym zatrzymaniu przepływu krwi do mózgu","Na równomiernym rozprowadzeniu krwi po całym ciele"],"correct":0,"explain":"Na skutek skurczu naczyń krew kierowana jest do najważniejszych narządów – mózgu, serca i płuc – kosztem mniej istotnych części ciała, np. kończyn."},{"type":"tf","q":"Siła mięśni rośnie o około 3% na każdy spadek temperatury ciała o 1 °C.","correct":false,"explain":"Jest odwrotnie – siła mięśni spada o około 3% na każdy spadek temperatury ciała o 1 °C, a mięśnie stają się sztywne i mniej elastyczne."},{"type":"tf","q":"Mimo chłodu w górach może dochodzić do odwodnienia organizmu.","correct":true,"explain":"Intensywne pocenie podczas podejścia, wysuszające powietrze oraz zwiększona diureza prowadzą do odwodnienia mimo niskiej temperatury."},{"type":"flash","front":"Jak należy przeciwdziałać skutkom niskiej temperatury podczas wysiłku w górach?","back":"Stosować odzież wielowarstwową i termoaktywną, dbać o regularne nawadnianie oraz planować tempo i przerwy umożliwiające regenerację i utrzymanie temperatury ciała."}]},{"id":"rek-cwiczenia-nadmierna-masa-ciala","track":"rekreacja","category":"rekreacja-spec","number":11,"title":"Ćwiczenia i aktywność dla osób z nadmierną masą ciała","summary":"Najistotniejsze zasady doboru ćwiczeń oraz zalecane formy aktywności fizycznej dla osób z nadwagą i otyłością, od konsultacji lekarskiej po dobór wysiłku tlenowego.","wiki":[{"heading":"Definicja i ocena","body":"Nadwaga i otyłość to nieprawidłowe lub nadmierne gromadzenie się tłuszczu, które stanowi zagrożenie dla zdrowia i zwiększa ryzyko wielu chorób niezakaźnych (cukrzyca, choroby sercowo-naczyniowe, niektóre nowotwory). Powszechnym wskaźnikiem oceny jest BMI, obrazujący stosunek masy ciała do wzrostu. Według klasyfikacji WHO osoby dorosłe z BMI 30 lub więcej są uznawane za otyłe, a z wynikiem 25 lub więcej — za osoby z nadwagą."},{"heading":"Zasady doboru ćwiczeń","bullets":["przed rozpoczęciem aktywności konieczna jest konsultacja lekarska w celu diagnozy chorób i przeciwwskazań","dobór ćwiczeń indywidualny — na podstawie możliwości, zdrowia, upodobań i stopnia otyłości","ćwiczenia powinny być dla pacjenta przyjemne i niesprawiające trudności, angażujące jak najwięcej grup mięśniowych","zajęcia grupowe motywują do systematyczności i poprawiają aspekt psychiczny i społeczny","w pierwszej kolejności zaleca się ćwiczenia w wodzie oraz jazdę na rowerze, które odciążają stawy kończyn dolnych i kręgosłup","podczas ćwiczeń nie wolno wstrzymywać oddechu — należy oddychać wolno i głęboko"]},{"heading":"Formy i intensywność aktywności","body":"Aktywność dzieli się na codzienną (każda forma ruchu, np. wchodzenie po schodach, unikanie wind, pieszy spacer) oraz planowaną. Według Brownella aktywność planowana powinna uwzględniać rodzaj, intensywność, czas trwania i częstotliwość. Typowe są ćwiczenia ogólnokondycyjne o średniej lub niskiej intensywności, angażujące duże grupy mięśniowe i wykonywane cyklicznie. Tętno docelowe do spalania tkanki tłuszczowej to 60-70% tętna maksymalnego. Zaleca się co najmniej 30 minut ćwiczeń o średniej intensywności dziennie, w miarę możliwości codziennie.","bullets":["metoda walk and talk: możliwość prowadzenia rozmowy podczas wysiłku świadczy o jego tlenowym charakterze","obowiązuje zasada, że jakakolwiek aktywność fizyczna jest lepsza niż żadna"]}],"questions":[{"type":"abcd","q":"Jaki zakres tętna maksymalnego stanowi tętno docelowe do ćwiczeń na spalanie tkanki tłuszczowej?","options":["40-50%","50-60%","60-70%","80-90%"],"correct":2,"explain":"Według źródła tętno docelowe do ćwiczeń na spalanie tkanki tłuszczowej to 60-70% tętna maksymalnego."},{"type":"abcd","q":"Jaką wartość BMI WHO przyjmuje jako granicę otyłości u osób dorosłych?","options":["25 lub więcej","28 lub więcej","30 lub więcej","35 lub więcej"],"correct":2,"explain":"Według klasyfikacji WHO osoby dorosłe z BMI wynoszącym 30 lub więcej są uznawane za otyłe, a z wynikiem 25 lub więcej — za osoby z nadwagą."},{"type":"tf","q":"Osoby z nadwagą i otyłością przed przystąpieniem do aktywności fizycznej powinny udać się na konsultację lekarską.","correct":true,"explain":"Źródło wskazuje, że w pierwszej kolejności należy udać się na konsultację lekarską w celu diagnozy chorób i przeciwwskazań do konkretnych aktywności."},{"type":"flash","front":"Wymień cechy ćwiczeń ogólnokondycyjnych stosowanych w leczeniu otyłości.","back":"Średni lub niski poziom intensywności (zakres docelowego tętna treningowego), efektywne zużycie tlenu przez pracujące mięśnie, angażowanie dużych grup mięśniowych kurczących się naprzemiennie oraz cykliczność i możliwość długotrwałego wysiłku bez przerw."}]},{"id":"rek-planowanie-dzialalnosci-rekreacyjnej","track":"rekreacja","category":"rekreacja-spec","number":12,"title":"Planowanie działalności rekreacyjnej w różnych środowiskach","summary":"Zasady planowania i programowania działalności rekreacyjnej dostosowanej do specyfiki miejsca zamieszkania, ośrodka wczasowego, zakładu pracy i hotelu.","wiki":[{"heading":"Podstawy planowania","body":"W planowaniu i programowaniu działalności rekreacyjnej ważne są: analiza rynku, zapewnienie bogatej oferty usług rekreacyjnych oraz działania marketingowe. Ofertę zawsze dostosowuje się do specyfiki środowiska i grupy odbiorców."},{"heading":"Miejsce zamieszkania i ośrodek wczasowy","bullets":["na osiedlu: wieczorne aktywności dla osób pracujących (8-16) oraz poranne dla kobiet w ciąży, z dziećmi i seniorów","stałe zajęcia ruchowe (fitness, nordic walking, joga) i wydarzenia (pikniki, spartakiady); przykładem jest program Trener Osiedlowy","ośrodek wczasowy: uwzględnia sezonowość (np. nad morzem duże obłożenie latem) oraz przedział wiekowy gości","rodziny potrzebują animacji dla dzieci i basenów, seniorzy spokojniejszych zajęć i opieki medycznej, osoby aktywne — wypożyczalni rowerów i sportów wodnych","krótkie turnusy wymagają intensywnego, atrakcyjnego i elastycznego programu rozrywkowo-sportowego"]},{"heading":"Zakład pracy i hotel","bullets":["zakład pracy: aktywności w czasie przerw lunchowych lub po godzinach pracy (tzw. 9-5 job)","w trakcie pracy warto zadbać o krótkie ćwiczenia rozluźniające i gimnastykę","hotel: sezonowość zależna od funkcjonowania hotelu oraz duża rotacja gości (pobyty 1-2 tygodnie)","oferta hotelowa powinna być bardzo atrakcyjna i nastawiona na „tu i teraz”, np. pakiety wellness z jogą, wstępem na basen lub siłownię"]}],"questions":[{"type":"abcd","q":"Co — według źródła — jest ważne w planowaniu i programowaniu działalności rekreacyjnej?","options":["analiza rynku, bogata oferta usług i działania marketingowe","wyłącznie obniżanie cen biletów","rezygnacja z działań marketingowych","jednolita oferta niezależna od środowiska"],"correct":0,"explain":"Źródło wymienia trzy elementy: analizę rynku, zapewnienie bogatej oferty usług rekreacyjnych oraz działania marketingowe."},{"type":"abcd","q":"Jaki czynnik trzeba szczególnie uwzględnić, planując działalność w ośrodku wczasowym nad morzem?","options":["brak jakiejkolwiek sezonowości","sezonowość — duże obłożenie w sezonie letnim i niemal zerowe poza nim","wyłącznie ofertę dla seniorów","całkowitą rezygnację z animacji dla dzieci"],"correct":1,"explain":"Funkcjonowanie ośrodka zależy od gości — nad polskim morzem oznacza to duże obłożenie latem i niemal zerowe poza sezonem."},{"type":"tf","q":"Oferta rekreacyjna w hotelu powinna być nastawiona na długofalowe budowanie sylwetki do kolejnego lata.","correct":false,"explain":"Przeciwnie — przez dużą rotację gości oferta hotelowa ma być atrakcyjna i nastawiona na „tu i teraz”, a nie na budowanie sylwetki do kolejnego lata."},{"type":"flash","front":"Jak rozplanować aktywności rekreacyjne dla mieszkańców osiedla?","back":"Wieczorne aktywności dla większości osób pracujących w godzinach 8-16 oraz poranne dla kobiet w ciąży, z dziećmi i seniorów; do tego dostęp do terenów rekreacyjnych, stałe zajęcia ruchowe (fitness, nordic walking, joga) i wydarzenia (pikniki, spartakiady)."}]},{"id":"rek-pomiary-antropometryczne","track":"rekreacja","category":"rekreacja-spec","number":13,"title":"Zasady wykonywania pomiarów antropometrycznych","summary":"Najważniejsze zasady prawidłowego wykonywania pomiarów antropometrycznych — od znajomości punktów ciała po dokładność zapisu.","wiki":[{"heading":"Najważniejsze zasady","bullets":["znajomość punktów antropometrycznych ciała","właściwa postawa ciała — w Polsce pomiary wykonuje się po lewej stronie ciała","odpowiedni strój, najlepiej sportowy, przylegający do ciała","dokładność odpowiednia do skali instrumentarium pomiarowego","odpowiednia pora wykonywania pomiarów","dokładność w zapisywaniu pomiarów"]}],"questions":[{"type":"abcd","q":"Po której stronie ciała wykonuje się w Polsce pomiary antropometryczne?","options":["po prawej stronie","po lewej stronie","naprzemiennie po obu stronach","wyłącznie z przodu ciała"],"correct":1,"explain":"Według źródła w Polsce pomiary antropometryczne wykonuje się po lewej stronie ciała przy zachowaniu właściwej postawy."},{"type":"tf","q":"Do pomiarów antropometrycznych zaleca się luźny, nieprzylegający strój, aby nie krępować ruchów.","correct":false,"explain":"Przeciwnie — źródło zaleca odpowiedni strój sportowy, najlepiej przylegający do ciała, oraz dokładność dostosowaną do skali instrumentarium pomiarowego."},{"type":"flash","front":"Wymień najważniejsze zasady wykonywania pomiarów antropometrycznych.","back":"Znajomość punktów antropometrycznych ciała, właściwa postawa (w Polsce po lewej stronie), odpowiedni przylegający strój sportowy, dokładność odpowiednia do skali instrumentarium, odpowiednia pora pomiarów oraz dokładność w zapisywaniu wyników."}]},{"id":"rek-zabawy-gry-ruchowe-seniorzy","track":"rekreacja","category":"rekreacja-spec","number":14,"title":"Rola zabaw i gier ruchowych w sprawności osób starszych","summary":"Funkcje, cele i zasady prowadzenia zabaw oraz gier ruchowych podtrzymujących ogólną sprawność fizyczną osób w wieku starszym.","wiki":[{"heading":"Funkcje zabaw i gier ruchowych","bullets":["kompensacyjna — rekompensuje ograniczenia wynikające z wieku","regeneracyjna — umożliwia aktywny odpoczynek, relaks i odbudowę sił psychicznych","rozrywkowa — dostarcza pozytywnych emocji, ważna wobec rosnącego ryzyka izolacji i smutku","antyinwolucyjna — przeciwdziała procesom starzenia się organizmu","kreacyjna — pozwala na kreatywność i rozwijanie pasji","afiliacyjna — sprzyja tworzeniu więzi i przynależności w grupie seniorów","integracyjna — aktywizuje seniorów z innymi grupami wiekowymi"]},{"heading":"Cele","bullets":["zapobieganie niepełnosprawności i chorobom wieku starczego (serca, narządu ruchu, metabolicznym)","poprawa odporności, koordynacji, czasu reakcji i siły, wzmocnienie mięśni","poprawa umiejętności motorycznych, zdrowia fizycznego i psychicznego oraz pracy mózgu","zabawa i rozrywka"]},{"heading":"Zasady prowadzenia zajęć","bullets":["pod kontrolą lekarską, z uwzględnieniem stanu zdrowia, oraz indywidualizacja zajęć","kameralna atmosfera i stosowanie łatwych przyborów","wprowadzanie ćwiczeń oddechowych w zwiększonym zakresie","mniejsze tempo ćwiczeń (temporalność) oraz urozmaicone, lecz stabilne pozycje wyjściowe","zadania o charakterze praktycznym"]}],"questions":[{"type":"abcd","q":"Która funkcja zabaw i gier ruchowych polega na przeciwdziałaniu procesom starzenia się organizmu?","options":["kompensacyjna","rozrywkowa","afiliacyjna","antyinwolucyjna"],"correct":3,"explain":"Funkcja antyinwolucyjna przeciwdziała procesom starzenia się organizmu, dzięki czemu seniorzy zachowują lepszą kondycję."},{"type":"tf","q":"Zajęcia ruchowe dla seniorów należy prowadzić w jak najszybszym tempie, aby maksymalnie obciążyć organizm.","correct":false,"explain":"Wręcz przeciwnie — źródło zaleca mniejsze tempo ćwiczeń (temporalność, realizacja zadań w wolniejszym tempie) oraz prowadzenie zajęć pod kontrolą lekarską."},{"type":"tf","q":"Funkcja afiliacyjna zabaw i gier ruchowych sprzyja tworzeniu więzi i poczucia przynależności w grupie seniorów.","correct":true,"explain":"Źródło opisuje funkcję afiliacyjną jako sprzyjającą tworzeniu więzi i przynależności wewnątrz grupy seniorów oraz przeciwdziałającą samotności i wykluczeniu."},{"type":"flash","front":"Wymień zasady prowadzenia zajęć ruchowych dla osób starszych.","back":"Kontrola lekarska i uwzględnienie stanu zdrowia, indywidualizacja zajęć, kameralna atmosfera, łatwe przybory, zwiększony zakres ćwiczeń oddechowych, mniejsze tempo (temporalność), urozmaicone, lecz stabilne pozycje wyjściowe oraz zadania o charakterze praktycznym."}]},{"id":"rek-miejska-turystyka-rowerowa","track":"rekreacja","category":"rekreacja-spec","number":15,"title":"Walory miejskiej turystyki rowerowej","summary":"Miejska turystyka rowerowa jako sposób spędzania wolnego czasu i źródło korzyści zdrowotnych, ekonomicznych, społecznych oraz ekologicznych.","wiki":[{"heading":"Czym jest miejska turystyka rowerowa","body":"Miejska turystyka rowerowa to przede wszystkim korzyści zdrowotne i metoda spędzania wolnego czasu. Zakłada podróżowanie rowerem po terenach miejskich w celach rekreacyjnych i turystycznych."},{"heading":"Walory","bullets":["poprawa kondycji i lepsze samopoczucie","profilaktyka zdrowotna","oszczędność kosztów oraz unikanie korków w mieście","kontakt z miastem i odkrywanie go z innej perspektywy","integracja społeczna, np. gdy zabieramy ze sobą bliskich","ochrona środowiska i promocja kultury rowerowej"]}],"questions":[{"type":"abcd","q":"Który z poniższych walorów wprost wynika z poruszania się rowerem zamiast samochodem w mieście?","options":["unikanie korków w mieście i oszczędność kosztów","zwiększenie emisji spalin","wzrost wydatków na paliwo","pogorszenie kondycji fizycznej"],"correct":0,"explain":"Źródło wymienia wśród walorów oszczędność kosztów oraz unikanie korków w mieście, a także ochronę środowiska."},{"type":"tf","q":"Miejska turystyka rowerowa sprzyja integracji społecznej, np. gdy zabieramy ze sobą bliskich.","correct":true,"explain":"Integracja społeczna — np. wspólne wyprawy z bliskimi — jest wymieniona w źródle jako jeden z walorów miejskiej turystyki rowerowej."},{"type":"flash","front":"Wymień walory miejskiej turystyki rowerowej.","back":"Poprawa kondycji, lepsze samopoczucie, profilaktyka zdrowotna, oszczędność kosztów, unikanie korków, kontakt z miastem i odkrywanie go z innej perspektywy, integracja społeczna, ochrona środowiska oraz promocja kultury rowerowej."}]},{"id":"rek-ksztalcenie-motoryczne-okresy-rozwojowe","track":"rekreacja","category":"rekreacja-spec","number":16,"title":"Proces kształcenia motorycznego w rekreacji fizycznej wg okresów rozwojowych","summary":"Kształcenie motoryczne przebiega odmiennie w kolejnych okresach życia człowieka — od burzliwego rozwoju motoryki w niemowlęctwie, przez dwa apogea motoryczności w dzieciństwie, kryzys w okresie pokwitania, aż po regres w starości.","wiki":[{"heading":"Wczesne dzieciństwo","body":"Okres niemowlęctwa cechuje się dużym tempem rozwoju motoryki: unoszenie głowy z tułowiem (ok. 3-4 miesiąca), obracanie się, ruchy chwytne i manipulacyjne, raczkowanie (od 5 do 7 miesiąca), siadanie (6-9 miesiąca) oraz pierwsze kroki (10-12 miesiąca). W okresie poniemowlęcym dziecko swobodnie chodzi, biega, doskonali równowagę, skacze, rzuca i kopie piłkę."},{"heading":"Apogea motoryczności","bullets":["I apogeum motoryczności — ok. 5 roku życia (okres przedszkolny), tzw. złoty okres motoryczności: rozrzutność ruchowa, przewaga procesów pobudzania nad hamowaniem, ruchy płynne, celowe i swobodne.","II apogeum motoryczności — okres młodszy szkolny: u dziewcząt w wieku 10-11 lat, u chłopców w wieku 12-13 lat. Dynamiczny rozwój wszystkich zdolności motorycznych i wyjątkowa łatwość uczenia się nowych, skomplikowanych ruchów (tzw. uczenie się z miejsca)."]},{"heading":"Pokwitanie, młodzieńczość i dorosłość","body":"Okres pokwitania to okres krytyczny w rozwoju motoryczności — pojawia się niezręczność w harmonii, dokładności i rytmie ruchu, szczególnie w ćwiczeniach gimnastycznych na przyrządach (ruchy acykliczne), przy ruchach precyzyjnych, kombinowanych oraz przy uczeniu nowych ruchów. W okresie młodzieńczym u osób nietrenujących występują maksymalne wartości większości zdolności motorycznych (zwłaszcza koordynacyjnych), kształtuje się indywidualny styl motoryczny i rozchodzą się linie rozwojowe kobiety i mężczyzny. Wiek dorosły i dojrzały nie sprzyja już rozwojowi motoryki."},{"heading":"Starość","bullets":["Wczesna starość: 60-75 rok życia; późna starość: powyżej 75 roku życia.","Zanik potrzeby ruchu i neofobia (strach przed uczeniem się nowego ruchu).","Zmniejszenie tempa ruchu, wydłużenie czasu reakcji, sztywność aparatu ruchu.","Sarkopenia — zanik włókien mięśniowych, spadek masy mięśniowej i obniżenie siły.","Obniżenie poziomu koordynacji ruchowej i ograniczenie ruchomości w stawach."]}],"questions":[{"type":"abcd","q":"W którym roku życia przypada I apogeum motoryczności, zwane złotym okresem motoryczności?","options":["Ok. 3 roku życia","Ok. 5 roku życia","Ok. 7 roku życia","Ok. 10 roku życia"],"correct":1,"explain":"I apogeum motoryczności (złoty okres) przypada na ok. 5 rok życia, w okresie przedszkolnym."},{"type":"abcd","q":"W jakim wieku przypada II apogeum motoryczności u chłopców?","options":["10-11 lat","8-9 lat","12-13 lat","14-15 lat"],"correct":2,"explain":"II apogeum motoryczności występuje u dziewcząt w wieku 10-11 lat, a u chłopców w wieku 12-13 lat."},{"type":"tf","q":"Okres pokwitania określa się jako okres krytyczny w rozwoju motoryczności, w którym pojawia się niezręczność ruchowa.","correct":true,"explain":"Pokwitanie to okres krytyczny — występują zakłócenia w harmonii, dokładności i rytmie ruchu, zwłaszcza przy ruchach acyklicznych i precyzyjnych."},{"type":"flash","front":"Wymień charakterystyczne cechy motoryczności w okresie starości.","back":"Zanik potrzeby ruchu, neofobia, zmniejszenie tempa ruchu, wydłużenie czasu reakcji, sztywność aparatu ruchu, sarkopenia (zanik włókien i spadek masy mięśniowej), obniżenie koordynacji oraz ograniczenie ruchomości w stawach."}]},{"id":"rek-recepta-ruchowa-niepelnosprawni","track":"rekreacja","category":"rekreacja-spec","number":17,"title":"Recepta ruchowa — ramowy program zajęć rekreacji dla osób z niepełnosprawnością","summary":"Ramowy program zajęć rekreacji fizycznej dla osób z niepełnosprawnością, zwany receptą ruchową, powinien zawierać konkretne kategorie informacji: od wskazań i przeciwwskazań, przez modyfikacje i techniki adaptacyjne, po dawkowanie wysiłku i metody samokontroli.","wiki":[{"heading":"Czym jest recepta ruchowa","body":"Recepta ruchowa to ramowy program zajęć rekreacji fizycznej przygotowany z myślą o osobach z niepełnosprawnością. Określa, jak bezpiecznie i skutecznie dobrać oraz dawkować aktywność ruchową w zależności od rodzaju dysfunkcji uczestnika."},{"heading":"Kategorie informacji w recepcie ruchowej","bullets":["Szczegółowe wskazania i przeciwwskazania do wykonywania poszczególnych zadań ruchowych.","Modyfikacja sposobu wykonywania zadań ruchowych w zależności od rodzaju występującej dysfunkcji.","Możliwości stosowania różnych technik adaptacyjnych w poszczególnych formach ruchu.","Optymalna częstotliwość i czas trwania zajęć rekreacyjnych.","Informacja o korzyściach płynących z danej formy rekreacji dla usprawniania leczniczego pacjenta.","Metody samokontroli tolerancji wysiłkowej pacjenta (zmęczenie, ból, tętno wysiłkowe itp.)."]}],"questions":[{"type":"abcd","q":"Który z elementów NIE należy do kategorii informacji recepty ruchowej?","options":["Wskazania i przeciwwskazania do zadań ruchowych","Techniki adaptacyjne w formach ruchu","Lista nagród za udział w zajęciach","Metody samokontroli tolerancji wysiłkowej"],"correct":2,"explain":"Recepta ruchowa obejmuje wskazania/przeciwwskazania, modyfikacje, techniki adaptacyjne, dawkowanie, korzyści i samokontrolę — nie zawiera listy nagród."},{"type":"tf","q":"Recepta ruchowa powinna zawierać metody samokontroli tolerancji wysiłkowej pacjenta, takie jak obserwacja zmęczenia, bólu czy tętna wysiłkowego.","correct":true,"explain":"Zgodnie ze źródłem recepta podaje metody samokontroli tolerancji wysiłkowej (zmęczenie, ból, tętno wysiłkowe itp.)."},{"type":"tf","q":"Recepta ruchowa zaleca jednakowy sposób wykonywania zadań ruchowych dla wszystkich, niezależnie od rodzaju dysfunkcji.","correct":false,"explain":"Przeciwnie — recepta wymaga modyfikacji sposobu wykonywania zadań ruchowych w zależności od rodzaju występującej dysfunkcji."},{"type":"flash","front":"Wymień kategorie informacji, które powinna zawierać recepta ruchowa.","back":"Wskazania i przeciwwskazania, modyfikacje zadań zależnie od dysfunkcji, techniki adaptacyjne, optymalna częstotliwość i czas trwania zajęć, informacja o korzyściach leczniczych oraz metody samokontroli tolerancji wysiłkowej."}]},{"id":"rek-piersieniowka-promocja-regionu","track":"rekreacja","category":"rekreacja-spec","number":18,"title":"Pierścieniówka jako polski sport promujący region turystyczny","summary":"Pierścieniówka to polska gra tradycyjna zbliżona do siatkówki, wymyślona w latach 30. XX wieku przez Władysława Robakowskiego. Dzięki obecności na festynach i imprezach integracyjnych stanowi element promujący region turystyczny.","wiki":[{"heading":"Zasady gry","body":"Pierścieniówka to polska gra tradycyjna, w której dwie drużyny (zazwyczaj 4 na 4) rywalizują, oburęcznie przerzucając piłkę przez siatkę z trzema otworami; środkowy otwór jest większy niż boczne. Można w nią grać na polu do siatkówki, potrzebna jest jednak specjalna siatka. Sport ten wymyślił w latach 30. XX wieku nauczyciel gimnastyki Władysław Robakowski."},{"heading":"Dostępność i promocja regionu","body":"Pierścieniówka to dynamiczna gra odpowiednia zarówno dla dzieci i młodzieży, jak i dorosłych, a także dla osób niepełnosprawnych, co udowodniło Stowarzyszenie Sportowo-Rehabilitacyjne START z Poznania. Bywa rozgrywana podczas festynów, imprez integracyjnych i świąt, takich jak Majówka, Dzień Dziecka, Jarmark Świętojański czy Festiwal Integracje w Poznaniu. Od momentu przywrócenia do życia jest coraz częściej pokazywana podczas ważnych imprez sportowych, w tym Światowych Igrzysk Sportów Tradycyjnych."}],"questions":[{"type":"abcd","q":"Kto wymyślił pierścieniówkę w latach 30. XX wieku?","options":["Władysław Robakowski","James Naismith","William G. Morgan","Stowarzyszenie START z Poznania"],"correct":0,"explain":"Pierścieniówkę wymyślił w latach 30. XX wieku nauczyciel gimnastyki Władysław Robakowski."},{"type":"abcd","q":"Ile otworów ma siatka używana w pierścieniówce?","options":["Dwa","Cztery","Trzy","Jeden"],"correct":2,"explain":"Siatka w pierścieniówce ma trzy otwory, przy czym środkowy jest większy niż boczne."},{"type":"tf","q":"Pierścieniówka jest grą, w którą mogą grać także osoby niepełnosprawne, co udowodniło Stowarzyszenie Sportowo-Rehabilitacyjne START z Poznania.","correct":true,"explain":"Źródło wskazuje, że pierścieniówka jest dostępna dla osób niepełnosprawnych, co potwierdziło poznańskie Stowarzyszenie START."},{"type":"flash","front":"Na czym polega gra w pierścieniówkę?","back":"Dwie drużyny (zazwyczaj 4 na 4) oburęcznie przerzucają piłkę przez siatkę z trzema otworami (środkowy większy niż boczne). Grać można na boisku do siatkówki, potrzebna jest jednak specjalna siatka."}]},{"id":"rek-gry-terenowe-miejskie-grupy-wiekowe","track":"rekreacja","category":"rekreacja-spec","number":19,"title":"Gry terenowe i miejskie dla różnych grup wiekowych i ich charakter edukacyjny","summary":"Gry terenowe i miejskie angażują wszystkie grupy wiekowe — od dzieci po seniorów — i pełnią funkcję edukacyjną: uczą korzystania z mapy i kompasu, współpracy, spostrzegawczości oraz poznawania przyrody i lokalnej kultury.","wiki":[{"heading":"Dzieci (6-12 lat)","bullets":["Skarb piratów — mapa z drogą do skarbu i zadaniami po drodze; uczy korzystania z mapy i współpracy.","Spacer po lesie — uzupełnianie zielnika w trakcie spaceru; łączy spacer z poznawaniem przyrody."]},{"heading":"Młodzież (13-18 lat)","bullets":["Skarb piratów z trudniejszymi zadaniami — uczy korzystania z mapy, kompasu i współpracy.","Podchody — podział na grupę „uciekającą” i „goniącą”; uczy poznawania obszaru, kreatywnego myślenia i współpracy."]},{"heading":"Dorośli (18+ lat)","bullets":["Geocaching — poszukiwanie ukrytych skrytek za pomocą telefonu; uczy cierpliwości, spostrzegawczości i poznawania terenu (skrytki zawierają notatki i ciekawostki o miejscu).","Bieg na orientację — bieg z mapą i kompasem do punktów kontrolnych; uczy planowania trasy i wpływa na sprawność fizyczną."]},{"heading":"Seniorzy (60+)","bullets":["Gra miejska — spacer po mieście z mapą i prostymi zadaniami związanymi z lokalną kulturą i przyrodą; aktywizuje ruchowo i umysłowo, trenuje pamięć i orientację oraz integruje uczestników."]}],"questions":[{"type":"abcd","q":"Która gra terenowa jest proponowana w źródle jako odpowiednia dla dorosłych (18+)?","options":["Podchody","Spacer po lesie","Skarb piratów","Geocaching"],"correct":3,"explain":"Dla dorosłych proponuje się geocaching oraz bieg na orientację; podchody i Skarb piratów to propozycje dla młodzieży/dzieci."},{"type":"abcd","q":"Czego głównie uczy gra miejska proponowana dla seniorów?","options":["Aktywizacji ruchowej i umysłowej, treningu pamięci i orientacji oraz integracji","Wyłącznie maksymalnego wysiłku fizycznego","Obsługi specjalistycznego sprzętu wspinaczkowego","Rywalizacji dwóch drużyn na czas"],"correct":0,"explain":"Gra miejska dla seniorów ma na celu aktywizację ruchową i umysłową, trening pamięci i orientacji oraz integrację z innymi uczestnikami."},{"type":"tf","q":"Gra „Skarb piratów” uczy korzystania z mapy i współpracy między uczestnikami.","correct":true,"explain":"Zgodnie ze źródłem Skarb piratów uczy korzystania z mapy oraz współpracy (u młodzieży dodatkowo kompasu)."},{"type":"flash","front":"Podaj przykład gry terenowej dla dzieci (6-12 lat) i wskaż jej walory edukacyjne.","back":"Spacer po lesie z uzupełnianiem zielnika — łączy spacer z poznawaniem przyrody. Alternatywnie Skarb piratów, który uczy korzystania z mapy i współpracy."}]},{"id":"rek-snooker-bilard-roznice","track":"rekreacja","category":"rekreacja-spec","number":20,"title":"Snooker i bilard — charakterystyka i różnice","summary":"Bilard i snooker to gry stołowe polegające na uderzaniu bil kijem i wbijaniu ich do otworów. Snooker wywodzi się z tradycyjnego bilarda, lecz różni się liczbą i wielkością bil, rozmiarem stołu, terminologią oraz bardziej zaawansowaną punktacją.","wiki":[{"heading":"Bilard","body":"Bilard to gra stołowa polegająca na uderzaniu bil za pomocą kija i wbijaniu ich do łuz. Używa się 16 bil — białej i 15 kolorowych. Może być grany pomiędzy dwoma graczami lub drużynami. Bile są ustawione w trójkąt, przy czym bile kolorowe i połówkowe są wymieszane."},{"heading":"Snooker","body":"Snooker to gra bilardowa wywodząca się od tradycyjnego bilarda. Grana jest na większym stole o tym samym kształcie, pomiędzy dwoma zawodnikami lub drużynami. Używa się 22 bil (15 czerwonych, 6 kolorowych i 1 biała). Bile czerwone są rozstawione w trójkąt, a kolorowe ustawione w określonych punktach na stole."},{"heading":"Najważniejsze różnice","bullets":["Liczba bil: w snookerze 22 (15 czerwonych, 6 kolorowych, 1 biała), w bilardzie 16 (15 kolorowych, 1 biała).","Wielkość bil: w snookerze są mniejsze; w snookerze nie ma numerków.","Terminologia: w snookerze „kieszenie”, w bilardzie „łuzy”.","Kij: w snookerze cieńszy; stół w snookerze większy (3,6 m wobec 2,8 m w bilardzie).","Punktacja: w snookerze bardziej zaawansowana — bile mają wartość od 2 do 7 pkt, w bilardzie po jednym punkcie (oprócz czarnej, która kończy rozgrywkę)."]}],"questions":[{"type":"abcd","q":"Ilu bil używa się w snookerze?","options":["16 bil","22 bile","15 bil","21 bil"],"correct":1,"explain":"W snookerze używa się 22 bil: 15 czerwonych, 6 kolorowych i 1 białej. W bilardzie jest ich 16."},{"type":"abcd","q":"Jak nazywa się otwory, do których wbija się bile, w terminologii bilardowej?","options":["Kieszenie","Bramki","Łuzy","Otwory"],"correct":2,"explain":"W bilardzie używa się terminu „łuzy”, natomiast w snookerze mówi się o „kieszeniach”."},{"type":"tf","q":"W snookerze stół jest większy niż w bilardzie, a kij cieńszy.","correct":true,"explain":"Zgodnie ze źródłem stół snookerowy jest większy (3,6 m wobec 2,8 m), a kij w snookerze jest cieńszy."},{"type":"tf","q":"W snookerze każda bila warta jest tyle samo punktów, podobnie jak w prostej punktacji bilardowej.","correct":false,"explain":"Przeciwnie — punktacja w snookerze jest bardziej zaawansowana: bile mają wartość od 2 do 7 punktów, podczas gdy w bilardzie liczone są po jednym punkcie."}]},{"id":"rek-pomiar-aktywnosci-i-sprawnosci-fizycznej","track":"rekreacja","category":"rekreacja-spec","number":21,"title":"Metody pomiaru aktywności i sprawności fizycznej w różnych grupach wiekowych","summary":"Aktywność fizyczną mierzy się metodami obiektywnymi i subiektywnymi, a sprawność fizyczną zestawami testów dobranymi do wieku, takimi jak HBSC, IPAQ, Eurofit czy Senior fitness test.","wiki":[{"heading":"Aktywność a sprawność fizyczna","body":"Aktywność fizyczna to ruch ciała wykonywany przez mięśnie szkieletowe, stanowiący element zdrowego stylu życia związany z rozwojem, zdrowiem i dobrym samopoczuciem. Jest ona aktywnością ruchową, ale nie każda aktywność ruchowa jest aktywnością fizyczną. Sprawność fizyczna to umiejętność rozwiązywania konkretnych zadań ruchowych oraz zdolność do efektywnego i ekonomicznego wykonywania pracy mięśniowej."},{"heading":"Metody pomiaru aktywności fizycznej","bullets":["obiektywne: bezpośrednie (np. kalorymetria bezpośrednia) i pośrednie (np. metoda podwójnie znakowanej wody, pomiar HR, kalorymetria pośrednia)","subiektywne: badania kwestionariuszowe oraz pisemna relacja","test IPAQ wyraża aktywność w jednostkach MET-min./tydzień, kwalifikując do aktywności niewystarczającej (poniżej 600), dostatecznej (600-1500) lub wysokiej (powyżej 1500)"]},{"heading":"Narzędzia dobrane do grup wiekowych","bullets":["dzieci: HBSC (badanie WHO co 4 lata wśród uczniów w wieku 11, 13 i 15 lat) oraz PAR oceniający wsparcie rodziców","dorośli (16-65 lat): IPAQ (aktywność w pracy, transporcie, rekreacji i obowiązkach domowych z ostatnich 7 dni) oraz Eurobarometr","osoby starsze: ADAPT (dzienniczek aktywności) oraz CHAMPS (samoocena aktywności seniorów)"]},{"heading":"Testy sprawności fizycznej","bullets":["Indeks Sprawności Fizycznej K. Zuchory - ocenia 6 cech motorycznych bez skomplikowanej aparatury","Eurofit - dla dzieci i młodzieży w wieku szkolnym 6-18 lat, bateria 9 prób","Alpha-fit - testy terenowe dla dorosłych Europejczyków w wieku 18-69 lat","Senior fitness test - wielowymiarowa ocena sprawności osób powyżej 60 r.ż."]}],"questions":[{"type":"abcd","q":"Które badanie aktywności fizycznej koordynowane przez WHO przeprowadza się co 4 lata wśród uczniów w wieku 11, 13 i 15 lat?","options":["IPAQ","Eurobarometr","HBSC","CHAMPS"],"correct":2,"explain":"HBSC (Health Behaviour in School-aged Children) to międzynarodowe badanie WHO realizowane co 4 lata wśród uczniów w wieku 11, 13 i 15 lat."},{"type":"abcd","q":"Dla jakiej grupy wiekowej przeznaczony jest Senior fitness test?","options":["Dla osób powyżej 60 r.ż.","Dla dzieci 6-18 lat","Dla dorosłych 18-69 lat","Dla uczniów 11-15 lat"],"correct":0,"explain":"Senior fitness test służy wielowymiarowej ocenie sprawności fizycznej osób w starszym wieku, powyżej 60 r.ż."},{"type":"tf","q":"Test IPAQ wyraża aktywność fizyczną w jednostkach MET-min./tydzień i pozwala zakwalifikować ją do jednej z trzech kategorii.","correct":true,"explain":"IPAQ wyraża aktywność w MET-min./tydzień, dzieląc ją na niewystarczającą (poniżej 600), dostateczną (600-1500) i wysoką (powyżej 1500)."},{"type":"flash","front":"Wymień narzędzia pomiaru aktywności fizycznej przeznaczone dla dorosłych (16-65 lat).","back":"IPAQ - kwestionariusz oceniający aktywność w pracy, transporcie, rekreacji i obowiązkach domowych z ostatnich 7 dni, oraz Eurobarometr - badanie opinii publicznej w krajach UE."}]},{"id":"rek-efekty-treningu-zdrowotnego","track":"rekreacja","category":"rekreacja-spec","number":22,"title":"Pożądane efekty treningu zdrowotnego w trzech płaszczyznach","summary":"Regularny trening zdrowotny przynosi korzyści w płaszczyźnie psychicznej, społecznej i fizycznej, od poprawy nastroju po redukcję ryzyka chorób przewlekłych.","wiki":[{"heading":"Czym jest trening zdrowotny","body":"Trening zdrowotny to trening skupiony na utrzymaniu lub poprawie zdrowia ćwiczącego. Wykonywany regularnie niesie za sobą szereg korzyści fizycznych, psychicznych oraz społecznych."},{"heading":"Płaszczyzna psychiczna","bullets":["poprawa nastroju i redukcja stresu","zwiększenie samooceny i pewności siebie","łagodzenie objawów depresji","zwiększenie motywacji do działania","poprawa funkcji poznawczych: pamięci i koncentracji"]},{"heading":"Płaszczyzna społeczna","bullets":["budowanie relacji i poczucia przynależności poprzez treningi grupowe","poprawa komunikacji i umiejętności interpersonalnych","redukcja poczucia samotności i izolacji, szczególnie istotna dla osób starszych"]},{"heading":"Płaszczyzna fizyczna","bullets":["wzmacnianie układu kostno-mięśniowego","poprawa wydolności krążeniowo-oddechowej","regulacja masy ciała i zapobieganie otyłości","redukcja ryzyka chorób przewlekłych (serca, cukrzycy typu 2, osteoporozy, nadciśnienia, niektórych nowotworów)","poprawa jakości snu"]}],"questions":[{"type":"abcd","q":"Który z poniższych efektów treningu zdrowotnego należy do płaszczyzny społecznej?","options":["Redukcja poczucia samotności i izolacji","Poprawa jakości snu","Wzmacnianie układu kostno-mięśniowego","Łagodzenie objawów depresji"],"correct":0,"explain":"Redukcja poczucia samotności i izolacji to efekt w płaszczyźnie społecznej; jakość snu i układ kostno-mięśniowy są fizyczne, a łagodzenie depresji psychiczne."},{"type":"tf","q":"Poprawa wydolności krążeniowo-oddechowej jest zaliczana do efektów treningu zdrowotnego w płaszczyźnie psychicznej.","correct":false,"explain":"Poprawa wydolności krążeniowo-oddechowej należy do płaszczyzny fizycznej, a nie psychicznej."},{"type":"flash","front":"Wymień przynajmniej trzy pożądane efekty treningu zdrowotnego w płaszczyźnie fizycznej.","back":"Wzmacnianie układu kostno-mięśniowego, poprawa wydolności krążeniowo-oddechowej, regulacja masy ciała, redukcja ryzyka chorób przewlekłych oraz poprawa jakości snu."}]},{"id":"rek-rekreacja-a-rozwiazywanie-konfliktow","track":"rekreacja","category":"rekreacja-spec","number":23,"title":"Wpływ rekreacji na rozwiązywanie konfliktów społecznych i zawodowych","summary":"Dzięki funkcji katartycznej i budowaniu relacji rekreacja sprzyja zdrowej komunikacji oraz radzeniu sobie ze stresem, co ułatwia rozwiązywanie konfliktów.","wiki":[{"heading":"Funkcja katartyczna","body":"Funkcja katartyczna (oczyszczająca) odnosi się do możliwości emocjonalnego odreagowania napięć i stresów poprzez aktywność fizyczną lub inne formy rekreacji. Jest to proces uwalniania negatywnych emocji prowadzący do odprężenia i poprawy samopoczucia, ważny dla zachowania równowagi psychicznej i fizycznej. Pozwala na odprężenie i redukcję stresu (ruch uwalnia endorfiny), uwolnienie emocji oraz katharsis, czyli oczyszczenie następujące po uwolnieniu napięć."},{"heading":"Wpływ na konflikty społeczne","bullets":["poprawa komunikacji poprzez wspólny sport i gry zespołowe","budowanie relacji, zaufania i empatii","redukcja stresu i napięcia towarzyszącego konfliktom","wzrost umiejętności negocjacyjnych dzięki grom zespołowym","tworzenie pozytywnej atmosfery wzajemnego szacunku"]},{"heading":"Wpływ na konflikty zawodowe","bullets":["budowanie zespołu poprzez wyjazdy integracyjne","poprawa komunikacji w zespole","redukcja stresu w pracy","rozwijanie umiejętności rozwiązywania konfliktów wymagających współpracy i negocjacji"]}],"questions":[{"type":"abcd","q":"Jak nazywa się funkcja rekreacji pozwalająca na emocjonalne oczyszczenie i odreagowanie napięć?","options":["Funkcja integracyjna","Funkcja negocjacyjna","Funkcja motywacyjna","Funkcja katartyczna"],"correct":3,"explain":"Funkcja katartyczna (oczyszczająca) pozwala na odreagowanie napięć i stresów oraz uwolnienie negatywnych emocji."},{"type":"tf","q":"Wyjazdy integracyjne i inne formy rekreacji mogą pomóc w budowaniu silnego zespołu, co zapobiega konfliktom zawodowym.","correct":true,"explain":"Budowanie zespołu poprzez wyjazdy integracyjne sprawia, że pracownicy chętniej współpracują, co przeciwdziała konfliktom zawodowym."},{"type":"flash","front":"W jaki sposób rekreacja wpływa na rozwiązywanie konfliktów społecznych?","back":"Poprawia komunikację, buduje relacje oparte na zaufaniu i empatii, redukuje stres, zwiększa umiejętności negocjacyjne i tworzy pozytywną atmosferę wzajemnego szacunku."}]},{"id":"rek-tance-regionalne-a-narodowe","track":"rekreacja","category":"rekreacja-spec","number":24,"title":"Różnice pomiędzy tańcami regionalnymi a narodowymi","summary":"Tańce regionalne związane są z konkretnym, niewielkim obszarem i tradycją lokalną, podczas gdy tańce narodowe reprezentują cały naród; w Polsce jest ich pięć.","wiki":[{"heading":"Definicje","bullets":["tańce regionalne - tańczone w określonym regionie kraju (np. Śląsk, Mazury), jak Hajduk na Żywiecczyźnie czy Wełto na Kaszubach","tańce narodowe - tańczone przez cały naród; w Polsce wyróżnia się 5 tańców narodowych","polskie tańce narodowe: polonez, mazur, krakowiak, kujawiak i oberek"]},{"heading":"Główne różnice","bullets":["strój - tańce regionalne mają charakterystyczne stroje związane z danym regionem","lokalizacja - regionalne na małym obszarze, narodowe reprezentują cały kraj","różnorodność - regionalne cechuje różnorodność ruchów, narodowe ich jednolitość","okoliczności - narodowe tańczono na salonach, regionalne głównie podczas obrzędów","historia - regionalne związane z tradycją lokalną, narodowe z całym narodem","w tańcach regionalnych stosuje się przyśpiewki"]}],"questions":[{"type":"abcd","q":"Ile tańców narodowych wyróżnia się w Polsce?","options":["Trzy","Pięć","Cztery","Siedem"],"correct":1,"explain":"W Polsce wyróżnia się 5 tańców narodowych: polonez, mazur, krakowiak, kujawiak i oberek."},{"type":"tf","q":"Tańce narodowe cechuje różnorodność ruchów, a tańce regionalne ich jednolitość.","correct":false,"explain":"Jest odwrotnie: to tańce regionalne cechuje różnorodność ruchów, a tańce narodowe ich jednolitość, bo wszędzie wyglądają tak samo."},{"type":"flash","front":"Wymień pięć polskich tańców narodowych.","back":"Polonez, mazur, krakowiak, kujawiak i oberek."}]},{"id":"rek-imprezy-rekreacyjne-promocja-zdrowia","track":"rekreacja","category":"rekreacja-spec","number":25,"title":"Rola imprez rekreacyjnych w promocji zdrowego stylu życia","summary":"Imprezy rekreacyjne to widowiska i zawody organizowane dla wypoczynku i rozwoju psychofizycznego, które motywują do aktywności, budują nawyki i sprzyjają profilaktyce zdrowotnej.","wiki":[{"heading":"Czym jest impreza rekreacyjna","body":"Impreza rekreacyjna to widowisko, koncert, zabawa lub zawody sportowe organizowane dla wypoczynku, rozrywki oraz podwyższania umiejętności i zdolności psychofizycznych uczestników. Jest to przedsięwzięcie dla dużej grupy odbiorców, jednorazowe lub cykliczne, w którym podstawowym środkiem działania programowego jest aktywność ruchowa oraz kulturalno-rozrywkowa."},{"heading":"Cele imprez rekreacyjnych","bullets":["popularyzacja rekreacyjnych form ruchowych","zaspokajanie potrzeb różnych środowisk w zakresie wzorów rekreacji ruchowej","rozbudzenie zainteresowań aktywnym wypoczynkiem","tworzenie warunków dla pozytywnie rozumianego współzawodnictwa","umożliwienie oceny sprawności fizycznej uczestników"]},{"heading":"Korzyści dla zdrowego stylu życia","bullets":["motywowanie do aktywności fizycznej i wykształcanie potrzeby ruchu","budowanie nawyków oraz uczenie dyscypliny i systematyczności","promowanie zdrowego odżywiania, snu i radzenia sobie ze stresem","integracja społeczna i budowanie poczucia wspólnoty","zabawa, radość i działanie na rzecz profilaktyki zdrowotnej"]}],"questions":[{"type":"abcd","q":"Co jest podstawowym środkiem działania programowego imprezy rekreacyjnej?","options":["Aktywność ruchowa oraz kulturalno-rozrywkowa","Wyłącznie rywalizacja sportowa wyczynowa","Bierny odpoczynek uczestników","Indywidualna terapia medyczna"],"correct":0,"explain":"W imprezie rekreacyjnej podstawowym środkiem działania programowego jest aktywność ruchowa oraz kulturalno-rozrywkowa."},{"type":"tf","q":"Imprezy rekreacyjne mają działać na rzecz profilaktyki zdrowotnej, zapobiegając chorobom związanym z brakiem ruchu.","correct":true,"explain":"Wśród korzyści wymienia się działanie na rzecz profilaktyki zdrowotnej poprzez zapobieganie chorobom z braku ruchu oraz promowanie zdrowego odżywiania."},{"type":"flash","front":"Wymień przynajmniej trzy cele imprez rekreacyjnych.","back":"Popularyzacja rekreacyjnych form ruchowych, zaspokajanie potrzeb różnych środowisk, rozbudzenie zainteresowań aktywnym wypoczynkiem, tworzenie warunków dla pozytywnego współzawodnictwa oraz umożliwienie oceny sprawności fizycznej."}]},{"id":"rek-zabawy-kreglarskie","track":"rekreacja","category":"rekreacja-spec","number":26,"title":"Zabawy kręglarskie w rekreacji ruchowej","summary":"Zabawy kręglarskie, takie jak Milionówka, Wyrzucany, Czarna kula, Gra rumuńska i Labinet, urozmaicają rekreację ruchową i często wywodzą się z treningu kręglarskiego.","wiki":[{"heading":"Milionówka i Wyrzucany","body":"Milionówka bierze nazwę od maksymalnej liczby punktów możliwych do uzyskania (999 999, czyli prawie milion). Liczba uczestników jest dowolna, a każdy po wylosowaniu kolejności wykonuje sześć rzutów, kolejno po jednym, wpisując wynik do jednej z sześciu rubryk. Wygrywa ten, kto ułoży wynik najbliższy milionowi. W Wyrzucanym liczba graczy jest dowolna; każdy stara się uzyskać rezultat lepszy od poprzednika w kolejce, a wynik gorszego przeciwnika się skreśla. Po ustalonej liczbie skreśleń gracz odpada, a wygrywa ten, kto ma ich najmniej."},{"heading":"Czarna kula i Gra rumuńska","body":"Czarna kula stosowana jest głównie jako trening w grze do uliczek. Grają dwie pięcioosobowe drużyny, każda na jednym torze, a w połowie gry następuje zmiana torów; ustawia się układy trzech kręgli (np. 1, 2, 4 lub 1, 3, 6). Wygrywa drużyna, która straci najwięcej układów „trójek”, a nazwa pochodzi od poznańskiego klubu „Czarna kula”. Gra rumuńska, wylansowana przez kręglarzy rumuńskich na torach klasycznych jako trening do zbieranych, daje na strącenie dziewięciu kręgli maksymalnie sześć rzutów, lecz punkty przyznaje tylko za strącenie „dziewiątki” w najwyżej trzech rzutach; pozostałe rzuty powodują odliczanie."},{"heading":"Labinet","body":"W Labinecie liczba graczy jest nieograniczona, a każdy oddaje kolejno po jednym rzucie. Na początku każdy otrzymuje 50 punktów minusowych i stara się je odrobić, a następnie nadrobić punkty plusowe. Wygrywa zawodnik, który pierwszy osiągnie 50 punktów na plus, czyli łącznie 100 punktów."}],"questions":[{"type":"abcd","q":"Od czego pochodzi nazwa zabawy Milionówka?","options":["Od liczby uczestników biorących udział w grze","Od maksymalnej liczby punktów możliwych do uzyskania (999 999)","Od liczby sześciu rzutów wykonywanych przez gracza","Od nazwy klubu kręglarskiego, w którym powstała"],"correct":1,"explain":"Nazwa pochodzi od maksymalnej liczby punktów (999 999, czyli prawie milion), jaką można zapisać w trakcie zabawy."},{"type":"tf","q":"W zabawie Labinet każdy gracz rozpoczyna od 50 punktów minusowych, a do zwycięstwa musi osiągnąć łącznie 100 punktów.","correct":true,"explain":"Grający startuje z 50 punktami minusowymi, odrabia je i nadrabia plusy; wygrywa pierwszy, kto osiągnie 50 plusów, czyli łącznie 100 punktów."},{"type":"tf","q":"W Czarnej kuli uczestniczą dwie dziesięcioosobowe drużyny grające bez zmiany torów.","correct":false,"explain":"W Czarnej kuli grają dwie pięcioosobowe drużyny, a w połowie gry następuje zmiana torów."},{"type":"flash","front":"Na czym polega Gra rumuńska?","back":"To trening do zbieranych na torach klasycznych: na strącenie dziewięciu kręgli gracz ma maksymalnie sześć rzutów, ale punkty zdobywa tylko za strącenie „dziewiątki” w najwyżej trzech rzutach; pozostałe rzuty powodują odliczanie. Wygrywa zawodnik z najwyższą liczbą punktów."}]},{"id":"rek-zachowania-zdrowotne","track":"rekreacja","category":"rekreacja-spec","number":27,"title":"Zachowania zdrowotne: prozdrowotne i ryzykowne","summary":"Zachowania zdrowotne to działania i nawyki wpływające na zdrowie pozytywnie (prozdrowotne) lub negatywnie (ryzykowne), a o samym zdrowiu najsilniej decyduje styl życia.","wiki":[{"heading":"Pojęcie zdrowia i jego uwarunkowania","body":"Zdrowie to nie tylko brak choroby czy kalectwa, ale stan pełnego dobrostanu fizycznego, umysłowego i społecznego. Obejmuje wymiary: fizyczny, psychiczny, społeczny, umysłowy, duchowy i seksualny. Na zdrowie najmocniej wpływa styl życia (50%), następnie czynniki genetyczne (20%), środowisko fizyczne i społeczne (20%) oraz służba zdrowia (10%). Kluczowe są też zdolność organizmu do utrzymania homeostazy oraz zasady salutogenezy, koncentrującej się na czynnikach sprzyjających zdrowiu."},{"heading":"Zachowania prozdrowotne","bullets":["aktywność fizyczna – regularne uprawianie sportu lub innej aktywności ruchowej","zdrowe odżywianie – posiłki bogate w warzywa, owoce, produkty pełnoziarniste, chude białko i zdrowe tłuszcze","unikanie używek oraz dbanie o higienę osobistą","regularne profilaktyczne wizyty u lekarza","wystarczająca ilość snu (7–8 h)","radzenie sobie ze stresem poprzez techniki relaksacyjne i aktywność fizyczną"]},{"heading":"Zachowania ryzykowne","bullets":["palenie tytoniu i nadużywanie alkoholu","niezdrowe odżywianie – dieta bogata w tłuszcze i cukry","brak aktywności fizycznej oraz stosowanie używek","zaniedbywanie zdrowia – brak wizyt u lekarza, ignorowanie objawów, samoleczenie","nadmierny, długotrwały stres","zbyt długie przesiadywanie z telefonem, komputerem lub telewizorem"]}],"questions":[{"type":"abcd","q":"Który czynnik w największym stopniu wpływa na zdrowie człowieka?","options":["Styl życia (ok. 50%)","Czynniki genetyczne (ok. 20%)","Środowisko fizyczne i społeczne (ok. 20%)","Służba zdrowia (ok. 10%)"],"correct":0,"explain":"Według podanych proporcji styl życia odpowiada za około 50% wpływu na zdrowie, najwięcej spośród wszystkich czynników."},{"type":"tf","q":"Zalecana ilość snu wskazana wśród zachowań prozdrowotnych to 7–8 godzin.","correct":true,"explain":"Wśród zachowań prozdrowotnych wymienia się wystarczającą ilość snu, czyli 7–8 godzin."},{"type":"tf","q":"Salutogeneza koncentruje się głównie na poszukiwaniu czynników chorobotwórczych i przyczyn chorób.","correct":false,"explain":"Salutogeneza koncentruje się na poszukiwaniu czynników sprzyjających zdrowiu i budowaniu zasobów pomagających adaptować się do stresorów."},{"type":"flash","front":"Wymień przykładowe zachowania ryzykowne zagrażające zdrowiu.","back":"Palenie tytoniu, nadużywanie alkoholu, niezdrowe odżywianie (dieta bogata w tłuszcze i cukry), brak aktywności fizycznej, stosowanie używek, zaniedbywanie zdrowia, nadmierny długotrwały stres oraz zbyt długie przesiadywanie z telefonem, komputerem lub telewizorem."}]},{"id":"rek-funkcje-rekreacji-niepelnosprawni","track":"rekreacja","category":"rekreacja-spec","number":28,"title":"Funkcje rekreacji osób z niepełnosprawnością","summary":"Rekreacja ruchowa osób z niepełnosprawnością pełni funkcje: leczniczą, pedagogiczno-psychologiczną, estetyczną, społeczną i ekonomiczną, co ilustrują konkretne formy zajęć.","wiki":[{"heading":"Funkcja lecznicza i pedagogiczno-psychologiczna","body":"Funkcja lecznicza stanowi część programu leczniczego: poprawia ekonomikę wysiłku, obniża wydatek energetyczny przy czynnościach i bywa substytutem środków farmakologicznych bez skutków ubocznych – jak hipoterapia (terapeutyczna jazda konna), w której ruchy konia korygują postawę, równowagę, koordynację i zmniejszają spastyczność mięśni. Funkcja pedagogiczno-psychologiczna kształtuje więzi społeczne i normuje postępowanie w grupie; przykładem są Olimpiady Specjalne, których celem nie jest wyłonienie mistrza, lecz danie możliwości przeżycia własnego startu – każdy startujący jest zwycięzcą."},{"heading":"Funkcja estetyczna i społeczna","body":"Funkcja estetyczna usprawnia ruch i kształtuje jego estetykę, maskując dysfunkcję ruchową oraz zaspokajając potrzebę piękna i harmonii; przykładem są zajęcia taneczne dla osób na wózkach inwalidzkich. Funkcja społeczna daje możliwość kontaktu z innymi ludźmi i tworzy pozytywne postawy społeczne wobec osób z niepełnosprawnością; ilustruje ją hortiterapia – prace w ogrodzie dające korzyści fizyczne oraz społeczne, takie jak otwartość na kontakt, współdziałanie i akceptacja społeczna."},{"heading":"Funkcja ekonomiczna","body":"Funkcja ekonomiczna zwiększa potencjał aktywności poprzez ogólne usprawnienie fizyczne oraz ekonomikę usprawnienia ruchowego. Przykładem jest udział osób z niepełnosprawnością w programach aktywizacji zawodowej obejmujących zajęcia rekreacyjne, co poprawia kondycję fizyczną, a tym samym zwiększa zdolność do podjęcia pracy i samodzielnego funkcjonowania w społeczeństwie."}],"questions":[{"type":"abcd","q":"Która funkcja rekreacji osób z niepełnosprawnością jest ilustrowana przykładem hipoterapii?","options":["Funkcja społeczna","Funkcja estetyczna","Funkcja lecznicza","Funkcja ekonomiczna"],"correct":2,"explain":"Hipoterapia to przykład funkcji leczniczej – ruchy konia korygują postawę, równowagę i koordynację oraz zmniejszają spastyczność mięśni."},{"type":"tf","q":"Celem Olimpiad Specjalnych jest wyłonienie mistrza uzyskującego najlepsze wyniki w danej konkurencji.","correct":false,"explain":"Celem Olimpiad Specjalnych nie jest wyłonienie mistrza, lecz danie możliwości przeżycia własnego startu – każdy startujący jest zwycięzcą."},{"type":"tf","q":"Hortiterapia, czyli prace w ogrodzie, jest przykładem społecznej funkcji rekreacji.","correct":true,"explain":"Hortiterapia ilustruje funkcję społeczną – oprócz korzyści fizycznych daje otwartość na kontakt, współdziałanie i akceptację społeczną."},{"type":"flash","front":"Wymień podstawowe funkcje rekreacji osób z niepełnosprawnością.","back":"Lecznicza, pedagogiczno-psychologiczna, estetyczna, społeczna oraz ekonomiczna."}]},{"id":"rek-zabawy-gry-zdolnosci-motoryczne","track":"rekreacja","category":"rekreacja-spec","number":29,"title":"Zabawy i gry kształtujące zdolności motoryczne","summary":"Różne rodzaje zabaw i gier ruchowych – ze śpiewem, orientacyjno-porządkowe, na czworakach, bieżne, rzutne, skoczne, kopne i słowne – kształtują wybrane zdolności motoryczne człowieka.","wiki":[{"heading":"Zabawy ze śpiewem oraz orientacyjno-porządkowe","body":"Zabawy ze śpiewem interesują dzieci w wieku 3–8 lat i osoby starsze; harmonizują ruch z rytmem i tempem muzyki, wywołują uśmiech i mają walor integracyjny (np. „Nitka”), wspierając poczucie rytmu, równowagi i orientację w przestrzeni. Gry orientacyjno-porządkowe stosuje się w grupach dzieci młodszych; uczą skupienia uwagi, słuchania poleceń, zasad fair play i porozumiewania się znakami, kształtując szybką i celową reakcję, spostrzegawczość oraz orientację (np. „Złośliwy wąż”)."},{"heading":"Zabawy na czworakach, bieżne i rzutne","body":"Zabawy na czworakach (np. „Pieski na spacer – pieski do domu”) stosuje się głównie u dzieci przedszkolnych i wczesnoszkolnych, bo sprzyjają kształtowaniu fizjologicznych krzywizn kręgosłupa, wzmacniają aparat kostno-stawowo-więzadłowy i siłę. Zabawy bieżne (np. „Lawina”) kształtują szybkość i wytrzymałość, a często też zręczność, i mogą być stosowane od wczesnej młodości do wieku podeszłego. Zabawy rzutne (np. „Zaganianie piłki świnki”) wymagają wstępnej nauki i rozwijają siłę, szybkość, koordynację oraz zręczność manualną."},{"heading":"Zabawy skoczne, kopne i słowne","body":"Zabawy skoczne opierają się na podskokach, skokach, wyskokach, przeskokach i doskokach (np. „Skoki konika”); rozwijają zwinność, szybkość i koordynację oraz wzmacniają stawy kończyn dolnych, lecz nie powinny być wykonywane przez osoby starsze. Zabawy kopne (np. „Piłkarska sztafeta wahadłowa”) interesują głównie chłopców i mężczyzn, kształtują zręczność, siłę i szybkość oraz angażują cały organizm poza kończynami górnymi. Zabawy słowne rozwijają kulturę słowa mówionego, angażują intelekt i można je łączyć z innymi grami ruchowymi."}],"questions":[{"type":"abcd","q":"Dlaczego zabawy i gry na czworakach stosuje się głównie u dzieci przedszkolnych i wczesnoszkolnych?","options":["Ponieważ rozwijają przede wszystkim wytrzymałość biegową","Ponieważ kształtują kulturę słowa mówionego","Ponieważ harmonizują ruch z rytmem muzyki","Ponieważ sprzyjają kształtowaniu fizjologicznych krzywizn kręgosłupa"],"correct":3,"explain":"Zabawy na czworakach sprzyjają kształtowaniu fizjologicznych krzywizn kręgosłupa i prawidłowej postawy ciała oraz wzmacniają aparat kostno-stawowo-więzadłowy."},{"type":"abcd","q":"Które zdolności motoryczne kształtują przede wszystkim zabawy i gry bieżne?","options":["Szybkość i wytrzymałość, a często też zręczność","Wyłącznie siłę kończyn górnych","Tylko poczucie rytmu","Wyłącznie precyzję ruchów rzutu"],"correct":0,"explain":"Zabawy i gry bieżne sprzyjają kształtowaniu szybkości i wytrzymałości, ale często też zręczności, w zależności od rodzaju zadania."},{"type":"tf","q":"Zabawy i gry skoczne są zalecane szczególnie dla osób w wieku starszym.","correct":false,"explain":"Zabawy skoczne wzmacniają sprawność głównie dzieci i młodzieży i nie powinny być wykonywane przez osoby w wieku starszym."},{"type":"flash","front":"Wymień rodzaje zabaw i gier ruchowych kształtujących zdolności motoryczne.","back":"Zabawy ze śpiewem, orientacyjno-porządkowe, na czworakach, bieżne, rzutne, skoczne, kopne oraz słowne."}]},{"id":"rek-folklor-kaszuby","track":"rekreacja","category":"rekreacja-spec","number":30,"title":"Folklor i region folklorystyczny – Kaszuby","summary":"Folklor to ogół tradycji, wierzeń, obyczajów, pieśni, tańców i opowieści kultury ludowej danej społeczności, a jednym z bogatych regionów folklorystycznych w Polsce są Kaszuby.","wiki":[{"heading":"Pojęcie folkloru","body":"Folklor to ogół tradycji, wierzeń, obyczajów, pieśni, tańców, opowieści i innych przejawów kultury ludowej charakterystycznych dla danej społeczności lub regionu. Jednym z bogatych regionów folklorystycznych w Polsce są Kaszuby, położone na Pomorzu."},{"heading":"Folklor Kaszub","bullets":["język kaszubski – odrębny język słowiański używany przez Kaszubów","stroje ludowe – bogata ornamentyka i kolorystyka z charakterystycznymi haftami; niebieski związany z morzem, a także czerwony, żółty i czarny","tańce i muzyka – m.in. taniec Wełtok (podobny do trojaka) oraz instrumenty ludowe, jak diabelskie skrzypce i burczybas (rodzaj bębna)","legendy i podania – opowieści o morskich potworach i tajemniczych postaciach","obrzędy i zwyczaje – związane z cyklem życia (chrzciny, wesela) i kalendarzem (sobótka, dożynki)","sztuka ludowa i kuchnia – rzeźba w drewnie, haft, ceramika oraz potrawy z ryb, ziemniaków i kapusty"]}],"questions":[{"type":"abcd","q":"Który element najlepiej oddaje definicję folkloru?","options":["Wyłącznie współczesna muzyka rozrywkowa danego kraju","Ogół tradycji, wierzeń, obyczajów, pieśni, tańców i opowieści kultury ludowej","Zbiór przepisów prawnych regulujących życie społeczności","Zestaw dyscyplin sportowych uprawianych w danym regionie"],"correct":1,"explain":"Folklor to ogół tradycji, wierzeń, obyczajów, pieśni, tańców, opowieści i innych przejawów kultury ludowej charakterystycznych dla danej społeczności lub regionu."},{"type":"tf","q":"Język kaszubski jest odrębnym językiem słowiańskim używanym przez Kaszubów.","correct":true,"explain":"W folklorze Kaszub wskazuje się język kaszubski jako odrębny język słowiański używany przez Kaszubów."},{"type":"tf","q":"Charakterystyczny dla kaszubskich strojów ludowych kolor niebieski jest związany z górami.","correct":false,"explain":"W kaszubskich strojach kolor niebieski związany jest z morzem; występują też czerwony, żółty i czarny."},{"type":"flash","front":"Podaj charakterystyczne elementy folkloru kaszubskiego.","back":"Język kaszubski, stroje ludowe o bogatej ornamentyce, tańce i muzyka (taniec Wełtok, instrumenty: diabelskie skrzypce i burczybas), legendy i podania, obrzędy i zwyczaje, sztuka ludowa oraz kuchnia oparta na rybach, ziemniakach i kapuście."}]}]$awfjson$::jsonb)
  as x(id text, track text, category text, number int, title text, summary text, wiki jsonb, questions jsonb)
